const item = $input.first();
const binaries = item.binary || {};
const keys = Object.keys(binaries);

let extractedText = "";
let filenames = [];

for (const key of keys) {
  const fileData = binaries[key];
  const fileName = fileData.fileName || key;
  filenames.push(fileName);

  try {
    let buffer;
    try {
      buffer = await this.helpers.getBinaryDataBuffer(0, key);
    } catch(e) {
      buffer = await this.helpers.getBinaryDataBuffer(key);
    }

    const text = buffer.toString('utf-8');
    if (text.includes('%PDF')) {
      extractedText += "\n--- DOCUMENT: " + fileName + " (Raw PDF) ---\n";
    } else {
      extractedText += "\n--- DOCUMENT: " + fileName + " ---\n" + text + "\n";
    }
  } catch (e) {
    extractedText += "\n--- DOCUMENT: " + fileName + " ---\n[Could not extract text]\n";
  }
}

return [{
  json: {
    files: keys,
    fileCount: keys.length,
    filenames: filenames,
    extractedText: extractedText,
    prompt: item.json.body?.prompt || '',
    policies: item.json.body?.policies || ''
  },
  binary: binaries
}];

