let raw = '';
try { raw = $input.first().json.output[0].content[0].text; }
catch(e) { try { raw = $input.first().json.output; } catch(e2) { raw = ''; } }

if (typeof raw !== 'string') raw = String(raw);
let clean = raw.replace(/```json/g, '').replace(/```/g, '').trim();

const prompt = ($('Extract Files').item.json.prompt || '').toLowerCase();
const fileCount = $('Extract Files').item.json.fileCount || 0;

let workflow = 'ai_audit';

// 1. Did user ask for CSV?
if (prompt.includes('csv') || prompt.includes('liquidation') || prompt.includes('export') || prompt.includes('table')) {
  workflow = 'data_normalization';
}
// 2. Are there 2+ files?
else if (fileCount >= 2) {
  workflow = 'comparison';
}
// 3. Otherwise trust AI
else {
  try {
    let parsed = JSON.parse(clean);
    if ( parsed.workflow === 'ai_audit' ||
      parsed.workflow === 'comparison' ||
      parsed.workflow === 'data_normalization'
    ) {
      workflow = parsed.workflow;
    }
    } catch (e) {
    workflow = 'ai_audit';
  }
}

// CARRY THE EXTRACTED TEXT AND PROMPTS FORWARD!
const extractedData = $('Extract Files').item.json.extractedText || '';
const policies = $('Extract Files').item.json.policies || '';
const userPrompt = $('Extract Files').item.json.prompt || '';
const filenames = $('Extract Files').item.json.filenames || [];

return [{
  json: {
    workflow: workflow,
    data: extractedData,
    prompt: userPrompt,
    policies: policies,
    filenames: filenames
  }
}];

const workflow = $('Clean Router JSON').item.json.workflow || 'ai_audit';

const extractText = (nodeName) => {
  try {
    const nodeData = $(nodeName).item.json;

    // 1. Fireworks API format
    if (nodeData.output && Array.isArray(nodeData.output)) {
      for (const message of nodeData.output) {
        if (message.content && Array.isArray(message.content)) {
          for (const part of message.content) {
            if (part.type === 'output_text' && part.text) return part.text;
          }
        }
      }
    }

    // 2. Groq / OpenAI format
    if (nodeData.choices && nodeData.choices[0]?.message?.content) {
      return nodeData.choices[0].message.content;
    }

    // 3. Simple text fallback
    if (typeof nodeData.text === 'string') return nodeData.text;

    return 'Could not extract text.';
  } catch (e) {
    return 'Node error';
  }
};

// Get the actual report text
const reportText = workflow === 'comparison' ? extractText('Comparison AI') : extractText('AI Audit AI');

// DYNAMIC ISSUE COUNTER: Count the red ❌ and yellow ⚠️ flags the AI made
const discrepancies = (reportText.match(/❌/g) || []).length;
const missing = (reportText.match(/⚠️/g) || []).length;
const issuesDetected = discrepancies + missing;

return [{ 
  json: {
    status: "success",
    workflow: workflow,
    summary: extractText('Generate Summary'),
    report: reportText,
    csv: workflow === 'liquidation' ? extractText('Liquidation AI') : "",
    filename: "audit_export.csv",
    metrics: {
      documentsProcessed: $('Extract Files').item.json.fileCount || 1,
      issuesDetected: issuesDetected, // NOW IT'S DYNAMIC!
      activeWorkflow: workflow
    }
  }
}];

